READ_FILE_TOOL = {
    "name": "read_file",
    "description": "Read file contents. Use offset/limit for windowed reads.",
    "input_schema": {
        "type": "object",
        "properties": {
            "path":   {"type": "string", "description": "Absolute path to the file."},
            "offset": {"type": "integer", "description": "1-indexed start line (optional)."},
            "limit":  {"type": "integer", "description": "Max lines to return (optional)."}
        },
        "required": ["path"]
    }
}

STR_REPLACE_TOOL = {
    "name": "str_replace_editor",
    "description": (
        "Replace an exact string in a file. "
        "old_str must appear exactly once; add context lines to ensure uniqueness."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "path":    {"type": "string", "description": "Absolute path to the file."},
            "old_str": {"type": "string", "description": "Exact string to replace (must be unique)."},
            "new_str": {"type": "string", "description": "Replacement text (empty string to delete)."}
        },
        "required": ["path", "old_str", "new_str"]
    }
}

import anthropic

client = anthropic.Anthropic()
tools = [READ_FILE_TOOL, WRITE_FILE_TOOL, STR_REPLACE_TOOL, SEARCH_FILES_TOOL]

EXECUTORS = {
    "read_file": read_file,
    "write_file": write_file,
    "str_replace_editor": str_replace_editor,
    "search_files": search_files,
}

def run_agent(task: str, max_rounds: int = 20) -> str:
    messages = [{"role": "user", "content": task}]
    for _ in range(max_rounds):
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=8192,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next(
                (b.text for b in response.content if b.type == "text"), ""
            )

        # Execute all tool calls in this turn
        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            executor = EXECUTORS.get(block.name)
            if executor is None:
                result = f"Error: unknown tool {block.name}"
            else:
                try:
                    result = executor(**block.input)
                except Exception as exc:
                    result = f"Error: {exc}"
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": result,
            })

        messages.append({"role": "user", "content": tool_results})

    return "Max rounds reached"

